@page "/board"
@using sv_895bb945add2430bbf8f5018e5990b97.Components.Layout
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

@if (isLoading)
{
    <div class="d-flex justify-content-center align-items-center" style="min-height: 300px;">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
    </div>
}
else
{
    <KanbanStatsBar AllTasks="allTasks" />

    <KanbanSearchBar SearchTerm="@searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="row g-3">
        @foreach (var col in columns)
        {
            var tasksInColumn = FilteredTasks.Where(t => t.Status == col).ToList();
            var colIndex = Array.IndexOf(columns, col);
            <div class="col-md-4">
                <KanbanColumn ColumnName="@col"
                              Tasks="tasksInColumn"
                              ShowMoveLeft="colIndex > 0"
                              ShowMoveRight="colIndex < columns.Length - 1"
                              OnMoveLeft="async (id) => await MoveTask(id, columns[colIndex - 1])"
                              OnMoveRight="async (id) => await MoveTask(id, columns[colIndex + 1])"
                              OnTaskCreated="OnTaskCreated" />
            </div>
        }
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] columns = { "To Do", "In Progress", "Done" };

    private IEnumerable<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(searchTerm)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void OnSearchChanged(string value)
    {
        searchTerm = value;
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            allTasks[allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task OnTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

::deep .kanban-column {
    background-color: #f8f9fa;
    border-radius: 0.5rem;
    min-height: 400px;
}

::deep .priority-high {
    background-color: #dc3545;
    color: #fff;
}

::deep .priority-medium {
    background-color: #ffc107;
    color: #212529;
}

::deep .priority-low {
    background-color: #198754;
    color: #fff;
}

@{
    var badgeClass = Task.Priority switch
    {
        "High" => "priority-high",
        "Medium" => "priority-medium",
        "Low" => "priority-low",
        _ => "bg-secondary"
    };
}

<div class="card mb-2">
    <div class="card-body p-2">
        <div class="fw-semibold mb-1">@Task.Title</div>
        <div class="d-flex justify-content-between align-items-center mb-1">
            <small class="text-muted">@Task.Assignee</small>
            <span class="badge @badgeClass">@Task.Priority</span>
        </div>
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div class="d-flex justify-content-between mt-2">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveLeft.InvokeAsync(Task.Id)">
                    &larr; Move Left
                </button>
            }
            else
            {
                <span></span>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveRight.InvokeAsync(Task.Id)">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveRight { get; set; }
}

